import{_ as a,o as s,c as n,ag as d}from"./chunks/framework.DGzMGr_a.js";const c=JSON.parse('{"title":"精益生产（Lean Production）","description":"","frontmatter":{},"headers":[],"relativePath":"standards/lean-production.md","filePath":"standards/lean-production.md","lastUpdated":null}'),i={name:"standards/lean-production.md"};function r(e,t,l,o,h,p){return s(),n("div",null,[...t[0]||(t[0]=[d(`<h1 id="精益生产-lean-production" tabindex="-1">精益生产（Lean Production） <a class="header-anchor" href="#精益生产-lean-production" aria-label="Permalink to &quot;精益生产（Lean Production）&quot;">​</a></h1><p>精益生产起源于丰田生产系统（Toyota Production System, TPS），核心理念是<strong>消除一切浪费、持续改善、创造价值</strong>。其目标是以最少的资源投入，在最短的时间内提供顾客满意的产品。</p><h2 id="七大浪费-timwood" tabindex="-1">七大浪费（TIMWOOD） <a class="header-anchor" href="#七大浪费-timwood" aria-label="Permalink to &quot;七大浪费（TIMWOOD）&quot;">​</a></h2><p>精益生产定义了七种核心浪费（也称 Muda），采用助记词 <strong>TIMWOOD</strong>：</p><table tabindex="0"><thead><tr><th>缩写</th><th>浪费类型</th><th>英文</th><th>示例</th></tr></thead><tbody><tr><td><strong>T</strong></td><td>运输浪费</td><td>Transport</td><td>物料不必要的搬运、远距离运输</td></tr><tr><td><strong>I</strong></td><td>库存浪费</td><td>Inventory</td><td>过多的原材料、在制品、成品库存</td></tr><tr><td><strong>M</strong></td><td>动作浪费</td><td>Motion</td><td>员工转身、弯腰、行走等不创造价值的动作</td></tr><tr><td><strong>W</strong></td><td>等待浪费</td><td>Waiting</td><td>等待物料、设备、信息、批准</td></tr><tr><td><strong>O</strong></td><td>过度加工浪费</td><td>Over-processing</td><td>超出顾客要求的加工精度或工序</td></tr><tr><td><strong>O</strong></td><td>过量生产浪费</td><td>Over-production</td><td>生产超出顾客需求的数量或过早生产</td></tr><tr><td><strong>D</strong></td><td>缺陷浪费</td><td>Defects</td><td>返工、报废、检查等由缺陷引起的成本</td></tr></tbody></table><blockquote><p>后期还增加了第 8 种浪费——<strong>人才浪费</strong>（未充分利用员工的创意和能力），形成 TIMWOODS。</p></blockquote><h3 id="浪费与增值活动" tabindex="-1">浪费与增值活动 <a class="header-anchor" href="#浪费与增值活动" aria-label="Permalink to &quot;浪费与增值活动&quot;">​</a></h3><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[所有活动] --&gt; B{创造价值？}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt;|是| C[增值活动&lt;br/&gt;改变形态或功能]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt;|否| D{必要？}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt;|是| E[必要非增值&lt;br/&gt;如检验、走流程]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt;|否| F[纯浪费&lt;br/&gt;需立即消除]</span></span></code></pre></div><p><strong>精益的目标</strong>：消除纯浪费，减少必要非增值活动，最大化增值活动比例。</p><h2 id="_5s-现场管理" tabindex="-1">5S 现场管理 <a class="header-anchor" href="#_5s-现场管理" aria-label="Permalink to &quot;5S 现场管理&quot;">​</a></h2><p>5S 是精益生产的基石，是创造有序、高效、安全工作环境的方法：</p><h3 id="_5s-的定义" tabindex="-1">5S 的定义 <a class="header-anchor" href="#_5s-的定义" aria-label="Permalink to &quot;5S 的定义&quot;">​</a></h3><table tabindex="0"><thead><tr><th>日语</th><th>中文</th><th>英文</th><th>核心要点</th></tr></thead><tbody><tr><td><strong>整理</strong><br>Seiri</td><td>整理</td><td>Sort</td><td>区分要与不要，清除无用物品</td></tr><tr><td><strong>整顿</strong><br>Seiton</td><td>整顿</td><td>Set in Order</td><td>物归其位，标识清晰，取用方便</td></tr><tr><td><strong>清扫</strong><br>Seiso</td><td>清扫</td><td>Shine</td><td>彻底清洁工作场所，发现异常</td></tr><tr><td><strong>清洁</strong><br>Seiketsu</td><td>清洁</td><td>Standardize</td><td>标准化，维持前 3S 的成果</td></tr><tr><td><strong>素养</strong><br>Shitsuke</td><td>素养</td><td>Sustain</td><td>养成习惯，持续遵守，形成文化</td></tr></tbody></table><h3 id="_5s-的实施步骤" tabindex="-1">5S 的实施步骤 <a class="header-anchor" href="#_5s-的实施步骤" aria-label="Permalink to &quot;5S 的实施步骤&quot;">​</a></h3><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart TD</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[1. 整理&lt;br/&gt;红牌作战] --&gt; B[2. 整顿&lt;br/&gt;定置管理]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; C[3. 清扫&lt;br/&gt;大扫除 + 点检]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; D[4. 清洁&lt;br/&gt;制定标准与制度]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; E[5. 素养&lt;br/&gt;培训与习惯养成]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt;|持续循环| A</span></span></code></pre></div><h3 id="_5s-的实施要点" tabindex="-1">5S 的实施要点 <a class="header-anchor" href="#_5s-的实施要点" aria-label="Permalink to &quot;5S 的实施要点&quot;">​</a></h3><ul><li><strong>整理</strong>：采用&quot;红牌作战&quot;——将不需要的物品贴上红牌，集中处理</li><li><strong>整顿</strong>：采用&quot;目视化管理&quot;和&quot;形迹管理&quot;——每个物品有固定位置和标识</li><li><strong>清扫</strong>：同时是检查过程，发现漏油、松动等异常及时处理</li><li><strong>清洁</strong>：建立 5S 检查标准和评分制度</li><li><strong>素养</strong>：通过晨会、培训、评比等方式将 5S 内化为员工习惯</li></ul><h2 id="kaizen-持续改善" tabindex="-1">Kaizen（持续改善） <a class="header-anchor" href="#kaizen-持续改善" aria-label="Permalink to &quot;Kaizen（持续改善）&quot;">​</a></h2><p><strong>Kaizen</strong>（改善）是精益生产的核心哲学——&quot;每天进步一点点&quot;。</p><h3 id="kaizen-的原则" tabindex="-1">Kaizen 的原则 <a class="header-anchor" href="#kaizen-的原则" aria-label="Permalink to &quot;Kaizen 的原则&quot;">​</a></h3><table tabindex="0"><thead><tr><th>原则</th><th>说明</th></tr></thead><tbody><tr><td><strong>打破现状</strong></td><td>即使没有明显问题，也要寻找改进机会</td></tr><tr><td><strong>过程导向</strong></td><td>关注过程改善，而非只关注结果</td></tr><tr><td><strong>全员参与</strong></td><td>一线员工最了解问题，鼓励全员提出改善建议</td></tr><tr><td><strong>低成本改善</strong></td><td>优先使用常识和创意，而非大量投资</td></tr><tr><td><strong>立即行动</strong></td><td>改善无需完美，今天能做的不要等到明天</td></tr></tbody></table><h3 id="kaizen-与-kaizen-blitz" tabindex="-1">Kaizen 与 Kaizen Blitz <a class="header-anchor" href="#kaizen-与-kaizen-blitz" aria-label="Permalink to &quot;Kaizen 与 Kaizen Blitz&quot;">​</a></h3><ul><li><strong>Kaizen</strong>：日常性、持续的改善活动（每天的小改善）</li><li><strong>Kaizen Blitz</strong>（改善突击）：集中 3–5 天对特定区域进行大刀阔斧的改善</li></ul><h3 id="kaizen-的实施流程" tabindex="-1">Kaizen 的实施流程 <a class="header-anchor" href="#kaizen-的实施流程" aria-label="Permalink to &quot;Kaizen 的实施流程&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 发现问题（现场观察、员工提案）</span></span>
<span class="line"><span>2. 分析现状（数据收集）</span></span>
<span class="line"><span>3. 根本原因分析（5 Why、鱼骨图）</span></span>
<span class="line"><span>4. 制定改善方案</span></span>
<span class="line"><span>5. 实施改善</span></span>
<span class="line"><span>6. 验证效果</span></span>
<span class="line"><span>7. 标准化（新标准作业）</span></span>
<span class="line"><span>8. 推广</span></span></code></pre></div><h2 id="jit-准时制生产" tabindex="-1">JIT（准时制生产） <a class="header-anchor" href="#jit-准时制生产" aria-label="Permalink to &quot;JIT（准时制生产）&quot;">​</a></h2><p><strong>JIT</strong>（Just-In-Time）的核心思想是&quot;在需要的时候，按需要的数量，生产需要的产品&quot;。</p><h3 id="jit-的三大要素" tabindex="-1">JIT 的三大要素 <a class="header-anchor" href="#jit-的三大要素" aria-label="Permalink to &quot;JIT 的三大要素&quot;">​</a></h3><table tabindex="0"><thead><tr><th>要素</th><th>说明</th></tr></thead><tbody><tr><td><strong>拉动式生产</strong></td><td>后工序仅在被需要时向前工序取料（Pull System）</td></tr><tr><td><strong>单件流</strong></td><td>尽可能实现单件流动，缩短生产周期</td></tr><tr><td><strong>节拍时间（Takt Time）</strong></td><td>按顾客需求速度生产</td></tr></tbody></table><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Takt Time = 可用工作时间 ÷ 顾客需求数量</span></span></code></pre></div><h3 id="jit-的前提条件" tabindex="-1">JIT 的前提条件 <a class="header-anchor" href="#jit-的前提条件" aria-label="Permalink to &quot;JIT 的前提条件&quot;">​</a></h3><ul><li>稳定的生产过程（低变异）</li><li>快速的换模换线（SMED）</li><li>多技能工（多能工）</li><li>可靠的设备维护（TPM）</li><li>高质量的来料（零缺陷思想）</li></ul><h2 id="看板系统-kanban" tabindex="-1">看板系统（Kanban） <a class="header-anchor" href="#看板系统-kanban" aria-label="Permalink to &quot;看板系统（Kanban）&quot;">​</a></h2><p>看板是 JIT 的信息传递工具，用于控制生产和物料的流动。</p><h3 id="看板的类型" tabindex="-1">看板的类型 <a class="header-anchor" href="#看板的类型" aria-label="Permalink to &quot;看板的类型&quot;">​</a></h3><table tabindex="0"><thead><tr><th>类型</th><th>用途</th></tr></thead><tbody><tr><td><strong>生产看板</strong></td><td>指示前工序生产的数量和顺序</td></tr><tr><td><strong>领取看板</strong></td><td>指示后工序领取物料的种类和数量</td></tr><tr><td><strong>信号看板</strong></td><td>用于批量生产工序的触发信号</td></tr></tbody></table><h3 id="看板的使用规则" tabindex="-1">看板的使用规则 <a class="header-anchor" href="#看板的使用规则" aria-label="Permalink to &quot;看板的使用规则&quot;">​</a></h3><ol><li>后工序只在需要时向前工序领取</li><li>前工序只生产后工序领取的数量</li><li>不合格品不送到后工序</li><li>看板数量应逐步减少（持续改善）</li><li>看板必须伴随实物</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>看板张数 = (平均需求 × 生产提前期 + 安全库存) ÷ 单箱容量</span></span></code></pre></div><h2 id="价值流图-vsm" tabindex="-1">价值流图（VSM） <a class="header-anchor" href="#价值流图-vsm" aria-label="Permalink to &quot;价值流图（VSM）&quot;">​</a></h2><p><strong>VSM</strong>（Value Stream Mapping，价值流图）是精益改善的核心分析工具，端到端可视化从原材料到成品的物料流和信息流。</p><h3 id="vsm-的标准符号" tabindex="-1">VSM 的标准符号 <a class="header-anchor" href="#vsm-的标准符号" aria-label="Permalink to &quot;VSM 的标准符号&quot;">​</a></h3><table tabindex="0"><thead><tr><th>符号</th><th>含义</th></tr></thead><tbody><tr><td>过程框</td><td>制造或信息处理过程</td></tr><tr><td>三角形</td><td>库存/缓冲区</td></tr><tr><td>闪电箭头</td><td>信息流（电子或人工）</td></tr><tr><td>卡车运输</td><td>外部运输/物流</td></tr><tr><td>数据框</td><td>过程数据（CT、C/O、可用率等）</td></tr></tbody></table><h3 id="vsm-分析步骤" tabindex="-1">VSM 分析步骤 <a class="header-anchor" href="#vsm-分析步骤" aria-label="Permalink to &quot;VSM 分析步骤&quot;">​</a></h3><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[选择产品族] --&gt; B[绘制现状图]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; C[识别浪费]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; D[绘制未来图]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; E[制定改善计划]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt; F[实施与跟踪]</span></span></code></pre></div><h3 id="关键指标" tabindex="-1">关键指标 <a class="header-anchor" href="#关键指标" aria-label="Permalink to &quot;关键指标&quot;">​</a></h3><table tabindex="0"><thead><tr><th>指标</th><th>含义</th><th>计算公式</th></tr></thead><tbody><tr><td><strong>CT</strong></td><td>周期时间</td><td>单件产品的加工时间</td></tr><tr><td><strong>C/O</strong></td><td>换模时间</td><td>从最后一个良品到下一个良品的时间</td></tr><tr><td><strong>Uptime</strong></td><td>设备可用率</td><td>设备可运行时间 ÷ 总时间</td></tr><tr><td><strong>LT</strong></td><td>交付前置期</td><td>从原材料到成品的总时间</td></tr><tr><td><strong>VA</strong></td><td>增值时间</td><td>实际改变形态的加工时间总和</td></tr><tr><td><strong>VA%</strong></td><td>增值率</td><td>VA / LT × 100%</td></tr></tbody></table><blockquote><p>多数企业的增值率不到 5%，这意味着 95% 以上的时间都是浪费或非增值活动。</p></blockquote><h2 id="精益生产与六西格玛的比较" tabindex="-1">精益生产与六西格玛的比较 <a class="header-anchor" href="#精益生产与六西格玛的比较" aria-label="Permalink to &quot;精益生产与六西格玛的比较&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>精益生产</th><th>六西格玛</th></tr></thead><tbody><tr><td><strong>关注点</strong></td><td>消除浪费，加速流动</td><td>减少变异，提升稳定性</td></tr><tr><td><strong>方法论</strong></td><td>5S、Kaizen、VSM、看板</td><td>DMAIC、统计工具</td></tr><tr><td><strong>主要工具</strong></td><td>目视化、SMED、TPM、看板</td><td>假设检验、DOE、SPC、FMEA</td></tr><tr><td><strong>改善力度</strong></td><td>渐进式 + 短期突击</td><td>项目制，持续数月</td></tr><tr><td><strong>适用场景</strong></td><td>流程过于复杂、周期过长</td><td>过程变异大、缺陷率高</td></tr></tbody></table><blockquote><p><strong>最佳实践</strong>：将精益生产与六西格玛结合 = <strong>Lean Six Sigma</strong>，用精益消除浪费，用六西格玛减少变异。</p></blockquote><h2 id="相关链接" tabindex="-1">相关链接 <a class="header-anchor" href="#相关链接" aria-label="Permalink to &quot;相关链接&quot;">​</a></h2><ul><li><a href="./six-sigma">六西格玛方法论</a></li><li><a href="./">ISO 9001 质量管理体系</a></li><li><a href="/tools/spc">SPC 统计过程控制</a></li><li><a href="/tools/fmea">FMEA 失效模式分析</a></li></ul>`,53)])])}const b=a(i,[["render",r]]);export{c as __pageData,b as default};
